import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  ENTP: "გამარჯობა 💡 მოდი ვიფიქროთ კრეატიულად შენს იდეებზე!",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო?"
};

export default function PersonalAIMentor({ userType, userId }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  const mbti = userType || "DEFAULT";
  const safeUserId = userId || localStorage.getItem("userId");

  // ===========================
  // history fetch
  // ===========================
  useEffect(() => {
    if (!safeUserId) return;

    const fetchHistory = async () => {
      try {
        const res = await fetch(
          `http://localhost:5000/api/chat-reply/history/${safeUserId}`
        );

        if (!res.ok) throw new Error("History fetch failed");

        const data = await res.json();

        if (data.history?.length > 0) {
          setMessages(data.history);
        } else {
          const first = firstMessages[mbti] || firstMessages.DEFAULT;
          setMessages([{ role: "ai", text: first }]);
        }
      } catch (err) {
        console.error("History error:", err);
        const first = firstMessages[mbti] || firstMessages.DEFAULT;
        setMessages([{ role: "ai", text: first }]);
      }
    };

    fetchHistory();
  }, [safeUserId, mbti]);

  // 👉 აქ ვამოწმებთ userId-ს (Hook-ის მერე!)
  if (!safeUserId) {
    return <div className="ai-mentor">გთხოვ გაიარე ავტორიზაცია 😊</div>;
  }

  // ===========================
  // send message
  // ===========================
  const sendMessage = async () => {
    if (!input.trim() || loading) return;

    const text = input;
    setInput("");
    setMessages(prev => [...prev, { role: "user", text }]);
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: text,
          type: mbti,
          userId: safeUserId,
          newChat: false
        })
      });

      if (!res.ok) throw new Error("Chat failed");

      const data = await res.json();
      setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
    } catch (err) {
      console.error("Send error:", err);
      setMessages(prev => [
        ...prev,
        { role: "ai", text: "😔 ჩატი დროებით მიუწვდომელია" }
      ]);
    }

    setLoading(false);
  };

  // ===========================
  // new chat
  // ===========================
  const newChat = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: "ახალი ჩატი დაიწყო",
          type: mbti,
          userId: safeUserId,
          newChat: true
        })
      });

      const data = await res.json();
      setMessages([{ role: "ai", text: data.reply }]);
    } catch (err) {
      console.error("New chat error:", err);
    }
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">
        Personal AI Mentor ({mbti})
        <button className="new-chat-btn" onClick={newChat}>
          New Chat
        </button>
      </div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="მომწერე..."
          rows="1"
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
        />
        <button onClick={sendMessage} disabled={loading}>
          გაგზავნა
        </button>
      </div>
    </div>
  );
}
